def divide(a, b):
    if b == 0:
        raise ValueError('cannot divide by zero')
    return a / b

def factorial(n):
    if n < 0:
        raise ValueError('negative')
    result = 1
    for i in range(2, n + 1):
        result *= i
    return result

def clamp(value, low, high):
    if low > high:
        raise ValueError('low > high')
    return max(low, min(value, high))

def to_upper(text):
    return text.upper()

def word_count(text):
    return len(text.split())
